-      "content": "\"\"\"\"\nConfiguration management using Pydantic settings.\n\"\"\"\nfrom typing import List, Optional\nfrom pydantic_settings import BaseSettings\nfrom pydantic import AnyHttpUrl, validator\nimport json\nimport os\n\nclass Settings(BaseSettings):\n    \"\"\"\n    Application settings loaded from environment variables.\n    \"\"\"\n    # Database\n    DATABASE_URL: str\n    POSTGRES_USER: str\n    POSTGRES_PASSWORD: str\n    POSTGRES_DB: str\n\n    # Redis\n    REDIS_URL: str\n\n    # Application\n    SECRET_KEY: str\n    ENVIRONMENT: str = \"development\"\n    LOG_LEVEL: str = \"INFO\"\n    API_V1_PREFIX: str = \"/api/v1\"\n\n    # CORS\n    BACKEND_CORS_ORIGINS: List[AnyHttpUrl] = []\n\n    @validator(\"BACKEND_CORS_ORIGINS\", pre=True)\n    def assemble_cors_origins(cls, v: str | List[str]) -> List[str] | str:\n        \"\"\"Parse CORS origins from string or list.\"\"\"\n        if isinstance(v, str) and not v.startswith(\"[\"):\n            return [i.strip() for i in v.split(\",\")]\n        elif isinstance(v, (list, str)):\n            return v\n        raise ValueError(v)\n\n    # Celery\n    CELERY_BROKER_URL: str = \"redis://redis:6379/1\"\n    CELERY_RESULT_BACKEND: str = \"redis://redis:6379/2\"\n\n    # File upload\n    MAX_UPLOAD_SIZE: int = 10 * 1024 * 1024  # 10MB\n    ALLOWED_UPLOAD_EXTENSIONS: List[str] = [\".json\", \".csv\", \".graphml\"]\n\n    # Graph settings\n    MAX_NODES_PER_GRAPH: int = 5000\n    MAX_EDGES_PER_GRAPH: int = 50000\n\n    class Config:\n        env_file = \".env\"\n        case_sensitive = True\n        extra = \"ignore\"  # Игнорировать лишние поля\n\n# Create global settings instance\nsettings = Settings()\n\n# Validate critical settings\nif settings.ENVIRONMENT == \"production\" and settings.SECRET_KEY == \"your-secret-key-here-change-in-production\":\n    raise ValueError(\"SECRET_KEY must be changed in production!\")\n",
