+      "content": "// frontend/src/App.tsx\nimport React, { useEffect, useState, useCallback, useMemo } from 'react';\nimport { useAppDispatch, useAppSelector } from './store';\nimport { fetchProjects } from './store/slices/projectsSlice';\nimport { updateArtifact, setCurrentArtifact, fetchArtifacts } from './store/slices/artifactsSlice';\nimport TabBar from './components/layout/TabBar';\nimport Sidebar from './components/layout/Sidebar';\nimport InspectorPanel from './components/layout/InspectorPanel';\nimport { GraphView } from './components/views/GraphView';\nimport { useActionWithUndo } from './hooks/useActionWithUndo';\nimport './App.css';\nimport './components/layout/TabBar.css';\n\ninterface Tab {\n  id: string;\n  artifactId: number;\n  title: string;\n  type: string;\n}\n\nfunction App() {\n  const dispatch = useAppDispatch();\n  const projects = useAppSelector((state) => state.projects.projects);\n  const currentProject = useAppSelector((state) => state.projects.currentProject);\n  const artifacts = useAppSelector((state) => state.artifacts.items);\n  const currentArtifactId = useAppSelector((state) => state.artifacts.currentArtifactId);\n  \n  const [tabs, setTabs] = useState<Tab[]>([]);\n  const [activeTabId, setActiveTabId] = useState<string | null>(null);\n  \n  const projectsCount = projects?.length ?? 0;\n\n  useEffect(() => {\n    dispatch(fetchProjects());\n  }, [dispatch]);\n\n  useEffect(() => {\n    if (currentProject?.id) {\n      dispatch(fetchArtifacts(currentProject.id));\n    }\n  }, [currentProject?.id, dispatch]);\n\n  const activeArtifact = useMemo(() => {\n    if (!activeTabId) return null;\n    const activeTab = tabs.find(t => t.id === activeTabId);\n    if (!activeTab) return null;\n    return artifacts[activeTab.artifactId];\n  }, [activeTabId, tabs, artifacts]);\n\n  const currentArtifactData = useMemo(() => {\n    return activeArtifact?.data || { nodes: [], edges: [] };\n  }, [activeArtifact]);\n\n  const { execute } = useActionWithUndo(\n    activeArtifact?.id || 0,\n    currentArtifactData,\n    async (newData) => {\n      if (activeArtifact) {\n        // Только обновляем Redux, API вызов уже сделан в execute\n        dispatch(updateArtifact({\n          projectId: activeArtifact.project_id,\n          id: activeArtifact.id,\n          updates: { data: newData }\n        }));\n      }\n    }\n  );\n\n  const handleNodeMove = useCallback(async (\n    nodeId: string, \n    x: number, \n    y: number, \n    groupId?: string | null\n  ) => {\n    if (!activeArtifact) return;\n\n    const currentData = artifacts[activeArtifact.id]?.data;\n    if (!currentData) {\n      console.error('[App] Artifact data not found in store');\n      return;\n    }\n\n    const afterState = {\n      ...currentData,\n      nodes: (currentData?.nodes || []).map((node: any) =>\n        node.id === nodeId\n          ? { ...node, position_x: Math.round(x), position_y: Math.round(y) }\n          : node\n      )\n    };\n\n    try {\n      await execute(\n        async () => afterState,\n        {\n          description: `Moving node ${nodeId}`,\n          actionType: 'move_node',\n          groupId: groupId || undefined\n        }\n      );\n    } catch (error) {\n      console.error('[App] Move failed:', error);\n    }\n  }, [activeArtifact, artifacts, execute]);\n\n  const handleNodesMove = useCallback(async (\n    moves: Array<{ nodeId: string; x: number; y: number }>,\n    groupId?: string | null\n  ) => {\n    if (!activeArtifact || moves.length === 0) return;\n\n    const currentData = artifacts[activeArtifact.id]?.data;\n    if (!currentData) {\n      console.error('[App] Artifact data not found in store');\n      return;\n    }\n\n    const moveMap = new Map(moves.map(m => [m.nodeId, { x: Math.round(m.x), y: Math.round(m.y) }]));\n    \n    const afterState = {\n      ...currentData,\n      nodes: (currentData?.nodes || []).map((node: any) => {\n        const move = moveMap.get(node.id);\n        return move\n          ? { ...node, position_x: move.x, position_y: move.y }\n          : node;\n      })\n    };\n\n    try {\n      await execute(\n        async () => afterState,\n        {\n          description: `Moving ${moves.length} nodes`,\n          actionType: 'batch_move',\n          groupId: groupId || undefined\n        }\n      );\n    } catch (error) {\n      console.error('[App] Batch move failed:', error);\n    }\n  }, [activeArtifact, artifacts, execute]);\n\n  const handleArtifactSelect = (artifact: any) => {\n    const existingTab = tabs.find(t => t.artifactId === artifact.id);\n    if (existingTab) {\n      setActiveTabId(existingTab.id);\n      dispatch(setCurrentArtifact(artifact.id));\n      return;\n    }\n    \n    const newTab: Tab = {\n      id: `tab-${artifact.id}-${Date.now()}`,\n      artifactId: artifact.id,\n      title: artifact.name,\n      type: artifact.type\n    };\n    \n    setTabs(prev => [...prev, newTab]);\n    setActiveTabId(newTab.id);\n    dispatch(setCurrentArtifact(artifact.id));\n  };\n\n  const handleTabClick = (tabId: string) => {\n    setActiveTabId(tabId);\n    const tab = tabs.find(t => t.id === tabId);\n    if (tab) {\n      dispatch(setCurrentArtifact(tab.artifactId));\n    }\n  };\n\n  const handleTabClose = (tabId: string) => {\n    setTabs(prev => prev.filter(t => t.id !== tabId));\n    if (activeTabId === tabId) {\n      const newActiveId = tabs.length > 1 ? tabs[0].id : null;\n      setActiveTabId(newActiveId);\n      if (newActiveId) {\n        const tab = tabs.find(t => t.id === newActiveId);\n        if (tab) {\n          dispatch(setCurrentArtifact(tab.artifactId));\n        }\n      } else {\n        dispatch(setCurrentArtifact(null));\n      }\n    }\n  };\n\n  const handleToggleCollapse = () => {};\n\n  if (!projects) {\n    return <div className=\"loading-screen\">Loading projects...</div>;\n  }\n\n  return (\n    <div className=\"app\">\n      <TabBar \n        tabs={tabs}\n        activeTabId={activeTabId}\n        onTabClick={handleTabClick}\n        onTabClose={handleTabClose}\n      />\n      <div className=\"main-layout\">\n        <Sidebar \n          isCollapsed={false}\n          onToggleCollapse={handleToggleCollapse}\n          onArtifactSelect={handleArtifactSelect}\n        />\n        <div className=\"content-area\">\n          {activeArtifact ? (\n            <GraphView \n              key={activeArtifact.id}\n              artifact={activeArtifact}\n              onNodeMove={handleNodeMove}\n              onNodesMove={handleNodesMove}\n            />\n          ) : (\n            <div className=\"no-selection\">\n              <h2>Select an artifact from the sidebar</h2>\n              <p>Use the sidebar to navigate projects and artifacts</p>\n            </div>\n          )}\n        </div>\n        <InspectorPanel />\n      </div>\n    </div>\n  );\n}\n\nexport default App;",
