+        await db.commit()
+        
+        # Обновляем кэш
+        cache = HistoryCache(redis_client)
+        await cache.clear(artifact_id)
+        
+        print(f"✅ Action {last_action.id} deleted")
+        
+        return {
+            "action_id": last_action.id,
